external_knowledge:
- 'Rewritten' refers to the action of editing a page;
- 'authors' refers to users who have performed the edit actions;
- 'granted the power of the pen' refers to having the permission to edit content, which is identified by the permission name 'edit_content'.

sql:
SELECT MAX(action_count) AS max_actions
FROM (
  SELECT user_id, COUNT(*) AS action_count
  FROM activity_logs
  GROUP BY user_id
);
